import { Injectable } from '@angular/core';
import { BehaviorSubject, Observable } from 'rxjs';
import { finalize } from 'rxjs/operators';

@Injectable({ providedIn: 'root' })
export class LoadingService {
  private counter = 0;
  private subject = new BehaviorSubject<boolean>(false);
  public loading$: Observable<boolean> = this.subject.asObservable();

  private update() {
    this.subject.next(this.counter > 0);
  }

  start(): void {
    this.counter++;
    this.update();
    
    // ✅ Timeout di sicurezza: se il loading dura più di 30 secondi, forza lo stop
    setTimeout(() => {
      if (this.counter > 0) {
        console.warn('⚠️ Loading timeout - forcing stop');
        this.counter = 0;
        this.update();
      }
    }, 20000);
  }

  stop(): void {
    this.counter = Math.max(0, this.counter - 1);
    this.update();
  }

  // utile per Promise
  trackPromise<T>(p: Promise<T>): Promise<T> {
    this.start();
    return p.finally(() => this.stop());
  }

  // utile per Observable: restituisce Observable che chiude il count al termine
  trackObservable<T>(obs$ : Observable<T>) {
    this.start();
    return obs$.pipe(finalize(() => this.stop()));
  }

  // getter comodo per verificare stato sync (opzionale)
  isLoadingSync(): boolean {
    return this.counter > 0;
  }
}
